function FaqItem({ q, a }) {
  const [open, setOpen] = useState(false);
  return (
    <div className="faq-item">
      <button className="faq-btn" onClick={() => setOpen(o => !o)}>
        {q}
        <span style={{ transform: open ? "rotate(180deg)" : "none", transition: "transform 0.3s", color: "rgba(255,255,255,0.3)", flexShrink: 0, fontSize: 18 }}>⌄</span>
      </button>
      <div style={{ maxHeight: open ? 300 : 0, overflow: "hidden", transition: "max-height 0.38s cubic-bezier(0.4,0,0.2,1)" }}>
        <p style={{ paddingBottom: 22, fontSize: 16, color: "rgba(255,255,255,0.45)", lineHeight: 1.75 }}>{a}</p>
      </div>
    </div>
  );
}

